input.command:
powershell -Command "
\$targets = @(
    '\$env:TEMP\chrome-debug-profile',
    '\$env:TEMP\node_modules',
    '\$env:TEMP\chocolatey',
    '\$env:TEMP\ecc',
    '\$env:TEMP\claude'
)
foreach (\$t in \$targets) {
    if (Test-Path \$t) {
        Remove-Item -Path \$t -Recurse -Force -ErrorAction SilentlyContinue
        Write-Host \"Deleted: \$t\"
    }
}
# Also clean playwright profiles
Get-ChildItem \$env:TEMP -Directory -Filter 'playwright_chromiumdev_profile-*' | ForEach-Object {
    Remove-Item \$_.FullName -Recurse -Force -ErrorAction SilentlyContinue
    Write-Host \"Deleted: \$(\$_.FullName)\"
}
Write-Host 'Done'
"

